ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
	name: "${mcp.server.name}",
	version: "${mcp.server.version}",
	description: "${mcp.server.description}",
	capabilities: {
		tools: {}
	},
	tools: [
		{
			name: "create-employee",
			description: "Create a new employee record in the system. Automatically generates employee ID if not provided and sets up initial employee profile for the onboarding process.",
			inputSchema: {
				"type": "object",
				properties: {
					employeeId: {
						"type": "string",
						description: "Unique identifier for the employee (auto-generated if not provided)"
					},
					firstName: {
						"type": "string",
						description: "Employee's first name"
					},
					lastName: {
						"type": "string",
						description: "Employee's last name"
					},
					email: {
						"type": "string",
						format: "email",
						description: "Employee's email address (must be unique)"
					},
					phone: {
						"type": "string",
						description: "Employee's phone number"
					},
					departmentId: {
						"type": "number",
						description: "Department ID (foreign key to departments table)"
					},
					position: {
						"type": "string",
						description: "Job title/position"
					},
					hireDate: {
						"type": "string",
						format: "date",
						description: "Employee hire date (YYYY-MM-DD format, defaults to current date)"
					},
					salary: {
						"type": "number",
						description: "Annual salary"
					},
					address: {
						"type": "string",
						description: "Employee's address"
					}
				},
				required: ["firstName", "lastName", "email"],
				additionalProperties: false
			}
		},
		{
			name: "get-employee",
			description: "Retrieve detailed information for a specific employee by their employee ID. Returns complete employee profile including current status and metadata.",
			inputSchema: {
				"type": "object",
				properties: {
					empId: {
						"type": "string",
						description: "Unique employee identifier (e.g., EMP001)"
					}
				},
				required: ["empId"],
				additionalProperties: false
			}
		},
		{
			name: "list-employees",
			description: "Retrieve a paginated list of employees with optional filtering by status. Supports pagination for efficient handling of large employee datasets.",
			inputSchema: {
				"type": "object",
				properties: {
					page: {
						"type": "number",
						minimum: 1,
						"default": 1,
						description: "Page number for pagination"
					},
					size: {
						"type": "number",
						minimum: 1,
						maximum: 100,
						"default": 10,
						description: "Number of employees per page"
					},
					status: {
						"type": "string",
						"enum": ["PENDING", "ACTIVE", "INACTIVE", "TERMINATED"],
						description: "Filter employees by status"
					}
				},
				additionalProperties: false
			}
		},
		{
			name: "update-employee-status",
			description: "Update the onboarding status of an employee. Supports standard employee lifecycle statuses and tracks status change history.",
			inputSchema: {
				"type": "object",
				properties: {
					empId: {
						"type": "string",
						description: "Unique employee identifier (e.g., EMP001)"
					},
					status: {
						"type": "string",
						"enum": ["PENDING", "ACTIVE", "INACTIVE", "TERMINATED"],
						description: "New status for the employee"
					}
				},
				required: ["empId", "status"],
				additionalProperties: false
			}
		}
	],
	resources: [
		{
			uri: "employees://profiles/all",
			name: "Employee Profiles",
			description: "Complete employee profile data including personal info, employment details, and status"
		},
		{
			uri: "employees://status/pending",
			name: "Pending Employees",
			description: "List of employees with pending onboarding status"
		},
		{
			uri: "employees://status/active",
			name: "Active Employees",
			description: "List of currently active employees"
		},
		{
			uri: "employees://analytics/metrics",
			name: "Employee Metrics",
			description: "Employee onboarding analytics and metrics"
		}
	]
}

%dw 2.0
output application/json
---
{
	content: [
		{
			"type": "text",
			text: "Employee created successfully with ID: " ++ payload.employeeId
		}
	],
	isError: false,
	result: payload
}

%dw 2.0
output application/json
---
if (payload.success == false)
	{
		content: [
			{
				"type": "text",
				text: payload.message
			}
		],
		isError: true,
		result: payload
	}
else
	{
		content: [
			{
				"type": "text",
				text: "Employee found: " ++ payload.first_name ++ " " ++ payload.last_name ++ " (" ++ payload.employee_id ++ ")"
			}
		],
		isError: false,
		result: payload
	}

%dw 2.0
output application/json
---
{
	content: [
		{
			"type": "text",
			text: "Found " ++ sizeOf(payload.data) ++ " employees on page " ++ payload.pagination.page
		}
	],
	isError: false,
	result: payload
}

%dw 2.0
output application/json
---
{
	content: [
		{
			"type": "text",
			text: "Employee status updated successfully: " ++ vars.empId ++ " -> " ++ vars.status
		}
	],
	isError: false,
	result: payload
}

%dw 2.0
output application/json
---
{
	content: [
		{
			"type": "text",
			text: "Invalid status: " ++ vars.status ++ ". Must be one of: PENDING, ACTIVE, INACTIVE, TERMINATED"
		}
	],
	isError: true,
	result: {
		success: false,
		error: "INVALID_STATUS",
		message: "Status must be one of: PENDING, ACTIVE, INACTIVE, TERMINATED",
		provided: vars.status
	}
}

db:select.db:input-parameters:
#[{
					statusFilter: vars.statusFilter,
					size: vars.size,
					offset: vars.offset
				}]

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
	success: true,
	data: payload,
	pagination: {
		page: vars.page,
		size: vars.size,
		totalResults: sizeOf(payload),
		hasMore: sizeOf(payload) == vars.size
	},
	filters: {
		status: vars.statusFilter
	},
	environment: "${env}",
	database: vars.databaseUsed,
	timestamp: now(),
	mockMode: vars.databaseUsed == "mock"
}

%dw 2.0
output application/java
---
{
	name: "database",
	healthy: true,
	status: "UP",
	details: {
		"type": vars.dbType,
		employeeCount: payload[0].employee_count,
		connection: "active"
	}
}

%dw 2.0
output application/java
---
{
	name: "database",
	healthy: false,
	status: "DOWN",
	details: {
		error: error.description,
		"type": "unavailable"
	}
}
